#include <bits/stdc++.h>
using namespace std;

const int MAX = 1000005;
long long n;
vector<pair<long long, int> > rst;
vector<int> primes;
bool vis[MAX];

int main() {
    cin >> n;
    for (int i = 2; i < MAX; i++) {
        if (!vis[i]) {
            primes.push_back(i);
            int cnt = 0;
            while (n % i == 0) {
                n /= i;
                cnt++;
            }
            if (cnt) rst.push_back(make_pair(i, cnt));
        }
        int len = primes.size();
        for (int j = 0; (j < len) && (i * primes[j] <= MAX); j++) {
            vis[i * primes[j]] = true;
            if (i % primes[j] == 0) break;
        }
    }
    if (n > 1) rst.push_back(make_pair(n, 1));
    int last = rst.size() - 1;
    for (int i = 0; i < last; i++) {
        if (rst[i].second == 1) printf("%lld * ", rst[i].first);
        else printf("%lld^%lld * ", rst[i].first, rst[i].second);
    }
    if (rst[last].second == 1) printf("%lld", rst[last].first);
    else printf("%lld^%lld", rst[last].first, rst[last].second);
    return 0;
}
